            doseMaxima: t(lang, 'Adultos: 320 mg/dia (HTA) / 320 mg/dia em 2 doses (IC) | Pediatria: 160 mg/dia', 'Adultos: 320 mg/día (HTA) / 320 mg/día en 2 dosis (IC) | Pediatría: 160 mg/día')
