            bioavailability: t(lang, '~25% (variável por metabolismo de primeira passagem; polimorfismo CYP2D6 pode aumentar até 2×)', '~25% (variable por metabolismo de primer paso; polimorfismo CYP2D6 puede aumentar hasta 2×)'),
