              ev: { dose: `0,25 mg/kg (≈${doseBolus} mg)`, intervalo: 'bolus IV lento 2 min; infusão: 5–15 mg/h', doseMaxima: '15 mg/h', unidade: 'mg/kg / mg/h' },
